      setPointsValue('');
      setReaisValue('');
      setPointsError(false);
      setReaisError(false);
      return () => {
        setPointsValue('');
        setReaisValue('');
        setPointsError(false);
        setReaisError(false);
      };
    }, [setPointsValue, setReaisValue])
  );

